import React, { useState } from "react";
import axios from "axios";
import { BrowserRouter, Routes, Route, Link } from "react-router-dom";
import CropDiseaseDetection from "./CropDiseaseDetection";
import AnimalDiseasePredictor from "./AnimalDiseasePredictor";

// ==========================
// DASHBOARD
// ==========================
function Dashboard() {
  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-green-50">
      <h1 className="text-4xl font-bold text-green-800 mb-10 text-center">
        Smart Agriculture Support System
      </h1>

      <div className="flex gap-6">
        <Link to="/recommendation">
          <button className="bg-green-600 text-white px-8 py-4 rounded-xl shadow-lg hover:bg-green-700">
            Crop Recommendation
          </button>
        </Link>

        <Link to="/disease">
          <button className="bg-emerald-600 text-white px-8 py-4 rounded-xl shadow-lg hover:bg-emerald-700">
            Disease Detection
          </button>
        </Link>
      </div>
    </div>
  );
}



// ==========================
// CROP RECOMMENDATION
// ==========================
function CropRecommendation() {
  const [location, setLocation] = useState("");
  const [season, setSeason] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setResult(null);

    try {
      const res = await axios.post("http://127.0.0.1:5000/predict", {
        location,
        season,
      });

      setResult(res.data);
    } catch (err) {
      alert("Server error. Check backend.");
      console.log(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-green-50 py-10 px-4">
      <div className="max-w-3xl mx-auto bg-white p-8 rounded-2xl shadow-xl">

        <h2 className="text-3xl font-bold text-green-700 mb-6">
          Crop Recommendation
        </h2>

        {/* FORM */}
        <form onSubmit={handleSubmit} className="space-y-4">
          <input
            type="text"
            placeholder="Enter city (Madurai, Erode...)"
            value={location}
            onChange={(e) => setLocation(e.target.value)}
            required
            className="w-full border p-3 rounded-lg"
          />

          <select
            value={season}
            onChange={(e) => setSeason(e.target.value)}
            required
            className="w-full border p-3 rounded-lg"
          >
            <option value="">Select Season</option>
            <option value="Kharif">Kharif</option>
            <option value="Rabi">Rabi</option>
            <option value="Summer">Summer</option>
          </select>

          <button
            type="submit"
            className="w-full bg-green-600 text-white py-3 rounded-lg hover:bg-green-700"
          >
            {loading ? "Analyzing..." : "Get Recommendation"}
          </button>
        </form>


        {/* ================= RESULTS ================= */}

        {result && (
          <div className="mt-8">

            {/* 🌆 URBAN MESSAGE */}
            {result.urban_farming_options && (
              <div className="bg-yellow-50 border border-yellow-200 p-5 rounded-xl mb-6">
                <h3 className="font-bold text-yellow-800 mb-2">
                  Urban Region Detected
                </h3>
                <p className="text-yellow-700 mb-3">
                  Large-scale farming may not be suitable here.
                  Try these terrace farming crops:
                </p>

                <div className="grid grid-cols-2 gap-3">
                  {result.urban_farming_options.map((crop, i) => (
                    <div key={i} className="bg-white p-3 rounded-lg shadow text-center font-semibold">
                      {crop}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* 🌾 TOP CROPS */}
            {result.top_recommendations && (
              <div>
                <h3 className="text-xl font-semibold text-gray-700 mb-4">
                  Top Suitable Crops
                </h3>

                <div className="grid md:grid-cols-3 gap-4">
                  {result.top_recommendations.map((item, index) => (
                    <div
                      key={index}
                      className="bg-green-50 border border-green-200 rounded-xl p-4 text-center"
                    >
                      <p className="text-xl font-bold text-green-700">
                        {item.crop}
                      </p>
                      <p className="text-sm text-gray-600">
                        Suitability: {item.suitability}
                      </p>
                    </div>
                  ))}
                </div>
              </div>
            )}

          </div>
        )}

      </div>
    </div>
  );
}



// ==========================
// MAIN APP ROUTER
// ==========================
function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Dashboard />} />
        <Route path="/recommendation" element={<CropRecommendation />} />
        <Route path="/disease" element={<CropDiseaseDetection />} />
        <Route path="/animal" element={<AnimalDiseasePredictor />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
